module RefModule(input [2:0] data_in, input clk, input reset, output reg [2:0] data_out);  
      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge reset or posedge dbg_halt) begin  
        if (reset)  
            data_out <= 3'b000;  
        else  
            data_out <= data_in >> 3;  
    end  
endmodule
